-- Patchnote 0.7.6 — idempotent seed (ON CONFLICT DO NOTHING).
INSERT INTO "Patchnote" ("version", "type", "date", "titleEn", "titleFr", "entries") VALUES
('0.7.6', 'patch', '2026-04-26T00:00:00.000Z',
  'Arch-aware plugin install + native-deps release guide',
  'Install plugin par architecture + guide deps natives',
  '[{"type":"feat","titleEn":"Arch-aware plugin install resolver","titleFr":"Résolveur d''install plugin par architecture","descEn":"Plugins that ship native modules (better-sqlite3, sharp, opt-in discord.js voice deps, …) can no longer fit a single universal asset — the .node binaries are baked at the arch where npm ci ran. The install resolver now picks an asset whose name carries an arch token matching the running container (arm64/aarch64 on ARM, amd64/x64/x86_64 on x86_64), falls back to a universal asset (no arch token), then to the source tarball. Plugin authors get to choose: ship one universal bundle, or a per-arch matrix.","descFr":"Les plugins qui livrent des modules natifs (better-sqlite3, sharp, deps voice optionnelles de discord.js, …) ne peuvent plus tenir dans un asset universel — les binaires .node sont compilés à l''archi où npm ci a tourné. Le résolveur d''install pioche maintenant un asset dont le nom contient un token d''arch matchant le container (arm64/aarch64 sur ARM, amd64/x64/x86_64 sur x86_64), fallback vers un asset universel (sans token d''arch), puis vers le tarball source. Les plugin authors choisissent : un bundle universel, ou une matrice per-arch."},{"type":"docs","titleEn":"Native-deps guide for plugin authors","titleFr":"Guide deps natives pour plugin authors","descEn":"docs/plugins.md ''Releasing a plugin'' expands with: the new resolution order, asset-contents requirements (no npm at runtime, all deps must be in the tarball), a ''bundling decision'' section explaining when to ship universal vs per-arch and listing common native-dep offenders (bcrypt vs bcryptjs, discord.js opt-ins, better-sqlite3, sharp, argon2, prisma), a shell snippet to find native deps in a plugin tree, a recommended universal-bundle workflow, and a complete per-arch matrix workflow template.","descFr":"docs/plugins.md ''Releasing a plugin'' s''enrichit : nouvel ordre de résolution, exigences sur le contenu d''asset (pas de npm au runtime, toutes les deps doivent être dans le tarball), une section ''bundling decision'' qui explique quand ship universel vs per-arch et liste les deps natives connues (bcrypt vs bcryptjs, opt-ins discord.js, better-sqlite3, sharp, argon2, prisma), un snippet shell pour trouver les deps natives dans un plugin, un workflow universel recommandé, et un template complet de matrice per-arch."}]'
) ON CONFLICT ("version") DO NOTHING;
